create or replace function public.mark_payroll_paid(p_organization_id uuid,p_payroll_run_id uuid,p_cash_account_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare r public.payroll_runs%rowtype; v_journal uuid; v_no text; payroll_payable uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient payroll payment permission'; end if; select * into r from public.payroll_runs where id=p_payroll_run_id and organization_id=p_organization_id for update; if not found or r.status<>'posted' then raise exception 'Posted payroll run not found'; end if; if not exists(select 1 from public.accounts where id=p_cash_account_id and organization_id=p_organization_id and account_subtype in ('cash','bank') and is_active) then raise exception 'Cash or bank account not found'; end if; select id into payroll_payable from public.accounts where organization_id=p_organization_id and code='2300'; v_no:=public.next_document_number(p_organization_id,'JE'); insert into public.journal_entries(organization_id,branch_id,entry_number,entry_date,memo,status,source_type,source_id,created_by) values(p_organization_id,r.branch_id,v_no,r.pay_date,'Payroll payment '||r.payroll_number,'draft','payroll_payment',r.id,p_actor_id) returning id into v_journal; insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,payroll_payable,'Payroll payable settled',r.net_pay,0),(p_organization_id,v_journal,p_cash_account_id,'Payroll paid',0,r.net_pay); update public.journal_entries set status='posted',posted_by=p_actor_id,posted_at=now() where id=v_journal; update public.payroll_runs set status='paid',payment_journal_entry_id=v_journal,paid_at=now(),updated_at=now() where id=r.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'payroll.run.paid','payroll_run',r.id,jsonb_build_object('number',r.payroll_number,'journal',v_journal,'amount',r.net_pay)); return jsonb_build_object('id',r.id,'number',r.payroll_number,'amount',r.net_pay); end $$;

revoke all on function public.mark_payroll_paid(uuid,uuid,uuid,uuid) from public;
grant execute on function public.mark_payroll_paid(uuid,uuid,uuid,uuid) to authenticated;